  ('elementary-0489de64-moex-00415', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '航空器使用人或運送人，若於託運前未向運送人聲明，就其託運貨物或登記行李之毀損或滅失所負之賠 償責任，每公斤最高不得超過新臺幣多少元？', '["1千元", "2千元", "3千元", "4千元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
